<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> _profiler </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> dhat</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Profiler</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new_heap</span><span style="color:#9399B2;">();</span></span>
